1	const PROCESSING_FEE = 5;
2	const COMPONENT_BASE_PREMIUM = 25;
3	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
4	const COMPONENT_BLOCK_SIZE = 3;
5	
6	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune"]);
14	
15	type Item = { type: string };
16	type QuoteStep = { op: "quote"; items: Item[] };
17	type Step = QuoteStep;
18	type Scenario = { customer: unknown; steps: Step[] };
19	type QuoteResult = { premium: number };
20	type StepResult = QuoteResult;
21	
22	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
23	
24	const basePremiumForItem = (item: Item): number =>
25	  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
26	
27	const partition = <T,>(items: T[], predicate: (item: T) => boolean): [T[], T[]] =>
28	  items.reduce<[T[], T[]]>(
29	    ([yes, no], item) => (predicate(item) ? [[...yes, item], no] : [yes, [...no, item]]),
30	    [[], []],
31	  );
32	
33	const countByType = (items: Item[]): Record<string, number> =>
34	  items.reduce<Record<string, number>>((acc, item) => {
35	    acc[item.type] = (acc[item.type] ?? 0) + 1;
36	    return acc;
37	  }, {});
38	
39	const componentGroupPremium = (count: number): number => {
40	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_BASE_PREMIUM;
41	  return count * COMPONENT_BASE_PREMIUM;
42	};
43	
44	const sumNonComponentPremiums = (items: Item[]): number =>
45	  items.reduce((total, item) => total + basePremiumForItem(item), 0);
46	
47	const sumComponentPremiums = (items: Item[]): number =>
48	  Object.values(countByType(items)).reduce(
49	    (sum, count) => sum + componentGroupPremium(count),
50	    0,
51	  );
52	
53	const totalBasePremium = (items: Item[]): number => {
54	  const [components, nonComponents] = partition(items, isComponent);
55	  return sumNonComponentPremiums(nonComponents) + sumComponentPremiums(components);
56	};
57	
58	const premiumForItems = (items: Item[]): number =>
59	  totalBasePremium(items) + PROCESSING_FEE;
60	
61	const quote = (step: QuoteStep): QuoteResult => ({
62	  premium: premiumForItems(step.items),
63	});
64	
65	export const processScenario = (input: Scenario): { results: StepResult[] } => ({
66	  results: input.steps.map(quote),
67	});
